namespace BgControls.Windows.Controls.DragDrop;public class LinearDropVisual : Control{    static LinearDropVisual()    {        DefaultStyleKeyProperty.OverrideMetadata(            typeof(LinearDropVisual),             new FrameworkPropertyMetadata(typeof(LinearDropVisual)));    }    protected override void OnInitialized(EventArgs e)    {        base.OnInitialized(e);        // StyleManager.SetDefaultStyleKey(this, typeof(LinearDropVisual));    }    internal void UpdateOrientationState(Orientation orientation)    {        VisualStateManager.GoToState(this, orientation.ToString(), useTransitions: true);    }}